  ('public-health-specialist-moex-00739', 'public-health-specialist', 'public-health-specialist-moex-111-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '為預防及治療精神疾病，支持及協助精神病人於社區生活，下列敘述何者與精神衛生法有關 規定不符？', '["精神照護機構設置監看設備，告知病人但未獲同意，為保障病人安全必要，對病人錄影", "精神醫療機構因醫療需要，限制住院精神病人會客及自由通訊", "精神醫療機構為防範病情不穩定之精神病人自殺，拘束病人身體", "嚴重病人依精神衛生法規定接受強制社區治療之費用，由全民健康保險予以給付"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "6b6c3604a0f7", "answer_pdf_sha1": "caf885c6f2e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
